121→// ---------------------------------------------------------------------------
122→// Create agent (atomic transaction)
123→// ---------------------------------------------------------------------------
124→
125→/**
126→ * Create an agent with identity, membership, authority scopes, and
127→ * optional proxy token in a single atomic transaction.
128→ *
129→ * Steps:
130→ * 1. Validate name uniqueness within workspace
131→ * 2. CREATE agent record
132→ * 3. CREATE identity record
133→ * 4. RELATE identity -> identity_agent -> agent
134→ * 5. RELATE identity -> member_of -> workspace
135→ * 6. For each of 11 actions: RELATE identity -> authorized_to -> authority_scope
136→ * 7. For external agents: generate and store proxy token
137→ */
138→export async function createAgentTransaction(
139→  surreal: Surreal,
140→  workspaceId: string,
141→  input: CreateAgentInput,
142→  now: Date,
143→): Promise<CreateAgentResult> {
144→  // Pre-validate name uniqueness
145→  const nameAvailable = await checkAgentName(surreal, workspaceId, input.name);
146→  if (!nameAvailable) {
147→    throw new HttpError(409, `Agent name '${input.name}' is already taken in this workspace`);
148→  }
149→
150→  const workspaceRecord = new RecordId("workspace", workspaceId);
151→  const agentId = randomUUID();
152→  const identityId = randomUUID();
153→  const agentRecord = new RecordId("agent", agentId);
154→  const identityRecord = new RecordId("identity", identityId);
155→
156→  // Build permission map from input, defaulting unconfigured actions to "propose"
157→  const permissionMap = buildPermissionMap(input.authority_scopes);
158→
159→  // Look up all authority_scope records for our actions to get the OUT targets
160→  const [scopeRows] = await surreal
161→    .query<[Array<{ id: RecordId<"authority_scope", string>; action: string }>]>(
162→      `SELECT id, action FROM authority_scope
163→       WHERE action IN $actions
164→       AND workspace IS NONE;`,
165→      { actions: [...AUTHORITY_ACTIONS] },
166→    );
167→
168→  const scopeByAction = new Map(
169→    scopeRows.map((row) => [row.action, row.id]),
170→  );
171→
172→  // Build the transaction SQL
173→  const statements: string[] = [];
174→  const bindings: Record<string, unknown> = {
175→    agentRecord,
176→    identityRecord,
177→    wsRecord: workspaceRecord,
178→    agentName: input.name,
179→    agentRuntime: input.runtime,
180→    agentType: "mcp", // custom agents default to "mcp" agent_type
181→    now,
182→  };
183→
184→  // Step 2: CREATE agent
185→  statements.push(
186→    `CREATE $agentRecord CONTENT {
187→      agent_type: $agentType,
188→      runtime: $agentRuntime,
189→      name: $agentName,
190→      ${input.description ? "description: $agentDescription," : ""}
191→      ${input.model ? "model: $agentModel," : ""}
192→      managed_by: $identityRecord,
193→      created_at: $now
194→      ${input.sandbox_config ? ", sandbox_config: $sandboxConfig" : ""}
195→    };`,
196→  );
197→
198→  if (input.description) bindings.agentDescription = input.description;
199→  if (input.model) bindings.agentModel = input.model;
200→  if (input.sandbox_config) bindings.sandboxConfig = input.sandbox_config;
201→
202→  // Step 3: CREATE identity
203→  statements.push(
204→    `CREATE $identityRecord CONTENT {
205→      name: $agentName,
206→      type: 'agent',
207→      role: 'custom',
208→      identity_status: 'active',
209→      workspace: $wsRecord,
210→      created_at: $now
211→    };`,
212→  );
213→
214→  // Step 4: RELATE identity -> identity_agent -> agent
215→  const identityAgentId = randomUUID();
216→  bindings.identityAgentRecord = new RecordId("identity_agent", identityAgentId);
217→  statements.push(
218→    `RELATE $identityRecord -> identity_agent -> $agentRecord
219→     CONTENT { added_at: $now };`,
220→  );
221→
222→  // Step 5: RELATE identity -> member_of -> workspace
223→  statements.push(
224→    `RELATE $identityRecord -> member_of -> $wsRecord
225→     CONTENT { role: 'agent', added_at: $now };`,
226→  );
227→
228→  // Step 6: RELATE identity -> authorized_to -> authority_scope for each action
229→  for (const action of AUTHORITY_ACTIONS) {
230→    const scopeRecord = scopeByAction.get(action);
231→    if (!scopeRecord) continue; // Skip if no global scope exists for this action
232→
233→    const permission = permissionMap.get(action) ?? "propose";
234→    const bindKey = `scope_${action}`;
235→    const permKey = `perm_${action}`;
236→    bindings[bindKey] = scopeRecord;
237→    bindings[permKey] = permission;
238→
239→    statements.push(
240→      `RELATE $identityRecord -> authorized_to -> $${bindKey}
241→       CONTENT { permission: $${permKey}, created_at: $now };`,
242→    );
243→  }
244→
245→  // Step 7: For external agents, generate proxy token
246→  let plainToken: string | undefined;
247→  if (input.runtime === "external") {
248→    plainToken = generateProxyToken();
249→    const tokenHash = hashProxyToken(plainToken);
250→    const ttlDays = readProxyTokenTtlDays();
251→    const expiresAt = computeExpiresAt(ttlDays, now);
252→    const proxyTokenId = randomUUID();
253→
254→    bindings.proxyTokenRecord = new RecordId("proxy_token", proxyTokenId);
255→    bindings.tokenHash = tokenHash;
256→    bindings.expiresAt = expiresAt;
257→
258→    statements.push(
259→      `CREATE $proxyTokenRecord CONTENT {
260→        token_hash: $tokenHash,
261→        workspace: $wsRecord,
262→        identity: $identityRecord,
263→        expires_at: $expiresAt,
264→        created_at: $now,
265→        revoked: false
266→      };`,
267→    );
268→  }
269→
270→  // Execute all statements in a single transaction
271→  const transactionSql = `BEGIN TRANSACTION;\n${statements.join("\n")}\nCOMMIT TRANSACTION;`;
272→  await surreal.query(transactionSql, bindings);
273→
274→  const agentListItem: AgentListItem = {
275→    id: agentId,
276→    name: input.name,
277→    ...(input.description ? { description: input.description } : {}),
278→    runtime: input.runtime,
279→    ...(input.model ? { model: input.model } : {}),
280→    identity_id: identityId,
281→    created_at: now.toISOString(),
282→  };
283→
284→  return {
285→    agent: agentListItem,
286→    ...(plainToken ? { proxy_token: plainToken } : {}),
287→  };
288→}
289→
290→function buildPermissionMap(
291→  scopes?: Array<{ action: AuthorityAction; permission: AuthorityPermission }>,
292→): Map<AuthorityAction, AuthorityPermission> {
293→  const map = new Map<AuthorityAction, AuthorityPermission>();
294→  if (!scopes) return map;
295→  for (const scope of scopes) {
296→    map.set(scope.action, scope.permission);
297→  }
298→  return map;
299→}
