301→// ---------------------------------------------------------------------------
302→// Get agent detail
303→// ---------------------------------------------------------------------------
304→
305→type AgentDetailRow = {
306→  id: RecordId<"agent", string>;
307→  name: string;
308→  description?: string;
309→  runtime: string;
310→  model?: string;
311→  sandbox_config?: SandboxConfig;
312→  created_at: string | Date;
313→};
314→
315→type IdentityRow = {
316→  id: RecordId<"identity", string>;
317→  name: string;
318→  type: string;
319→  role?: string;
320→};
321→
322→type AuthorizedToRow = {
323→  action: string;
324→  permission: string;
325→};
326→
327→type SessionRow = {
328→  id: RecordId<"agent_session", string>;
329→  started_at: string | Date;
330→  ended_at?: string | Date;
331→  orchestrator_status?: string;
332→  summary?: string;
333→};
334→
335→/**
336→ * Get full agent detail including identity, authority scopes, and
337→ * recent workspace sessions.
338→ */
339→export async function getAgentDetail(
340→  surreal: Surreal,
341→  workspaceId: string,
342→  agentId: string,
343→): Promise<AgentDetail | undefined> {
344→  const workspaceRecord = new RecordId("workspace", workspaceId);
345→  const agentRecord = new RecordId("agent", agentId);
346→
347→  // Query agent, identity, authorized_to edges, and sessions in one round-trip
348→  const results = await surreal
349→    .query<[AgentDetailRow[], IdentityRow[], AuthorizedToRow[], SessionRow[]]>(
350→      `SELECT id, name, description, runtime, model, sandbox_config, created_at
351→       FROM $agent;
352→
353→       SELECT id, name, type, role
354→       FROM identity
355→       WHERE id IN (
356→         SELECT VALUE in FROM identity_agent WHERE out = $agent
357→       )
358→       AND workspace = $ws
359→       LIMIT 1;
360→
361→       SELECT out.action AS action, permission
362→       FROM authorized_to
363→       WHERE in IN (
364→         SELECT VALUE in FROM identity_agent WHERE out = $agent
365→       )
366→       ORDER BY action ASC;
367→
368→       SELECT id, started_at, ended_at, orchestrator_status, summary
369→       FROM agent_session
370→       WHERE workspace = $ws
371→       ORDER BY started_at DESC
372→       LIMIT 20;`,
373→      { agent: agentRecord, ws: workspaceRecord },
374→    );
375→
376→  const [agentRows, identityRows, authorizedToRows, sessionRows] = results;
377→
378→  if (agentRows.length === 0 || identityRows.length === 0) {
379→    return undefined;
380→  }
381→
382→  const agentRow = agentRows[0];
383→  const identityRow = identityRows[0];
384→
385→  const agentListItem: AgentDetail["agent"] = {
386→    id: agentRow.id.id as string,
387→    name: agentRow.name,
388→    ...(agentRow.description ? { description: agentRow.description } : {}),
389→    runtime: agentRow.runtime as AgentListItem["runtime"],
390→    ...(agentRow.model ? { model: agentRow.model } : {}),
391→    identity_id: identityRow.id.id as string,
392→    created_at: toISOString(agentRow.created_at),
393→    ...(agentRow.sandbox_config ? { sandbox_config: agentRow.sandbox_config } : {}),
394→  };
395→
396→  return {
397→    agent: agentListItem,
398→    identity: {
399→      id: identityRow.id.id as string,
400→      name: identityRow.name,
401→      type: identityRow.type,
402→      ...(identityRow.role ? { role: identityRow.role } : {}),
403→    },
404→    authority_scopes: authorizedToRows.map((row) => ({
405→      action: row.action,
406→      permission: row.permission,
407→    })),
408→    sessions: sessionRows.map(toSessionSummary),
409→  };
410→}
411→
412→function toSessionSummary(row: SessionRow): SessionSummary {
413→  return {
414→    id: row.id.id as string,
415→    started_at: toISOString(row.started_at),
416→    ...(row.ended_at ? { ended_at: toISOString(row.ended_at) } : {}),
417→    ...(row.orchestrator_status ? { orchestrator_status: row.orchestrator_status } : {}),
418→    ...(row.summary ? { summary: row.summary } : {}),
419→  };
420→}
