  1→/**
  2→ * Agent Domain Types
  3→ *
  4→ * Types for the agent CRUD module. Defines the domain model for
  5→ * custom agent creation, authority scope configuration, and
  6→ * lifecycle management.
  7→ */
  8→
  9→// ---------------------------------------------------------------------------
 10→// Runtime classification
 11→// ---------------------------------------------------------------------------
 12→
 13→/** How the agent executes: brain-managed, sandboxed, or external. */
 14→export type AgentRuntime = "brain" | "sandbox" | "external";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Authority actions and permissions
 18→// ---------------------------------------------------------------------------
 19→
 20→/** The 11 configurable authority actions an agent can be scoped to. */
 21→export type AuthorityAction =
 22→  | "create_decision"
 23→  | "confirm_decision"
 24→  | "create_task"
 25→  | "complete_task"
 26→  | "create_observation"
 27→  | "acknowledge_observation"
 28→  | "resolve_observation"
 29→  | "create_question"
 30→  | "create_suggestion"
 31→  | "create_intent"
 32→  | "submit_intent";
 33→
 34→/** All 11 actions as a constant array for iteration and validation. */
 35→export const AUTHORITY_ACTIONS: readonly AuthorityAction[] = [
 36→  "create_decision",
 37→  "confirm_decision",
 38→  "create_task",
 39→  "complete_task",
 40→  "create_observation",
 41→  "acknowledge_observation",
 42→  "resolve_observation",
 43→  "create_question",
 44→  "create_suggestion",
 45→  "create_intent",
 46→  "submit_intent",
 47→] as const;
 48→
 49→/** Permission level for an authority scope. */
 50→export type AuthorityPermission = "auto" | "propose" | "blocked";
 51→
 52→// ---------------------------------------------------------------------------
 53→// Input types
 54→// ---------------------------------------------------------------------------
 55→
 56→/** Sandbox configuration for sandbox-runtime agents. */
 57→export type SandboxConfig = {
 58→  coding_agents?: string[];
 59→  env_vars?: Array<{ key: string; value: string }>;
 60→  image?: string;
 61→  snapshot?: string;
 62→};
 63→
 64→/** Authority scope input for agent creation. */
 65→export type AuthorityScopeInput = {
 66→  action: AuthorityAction;
 67→  permission: AuthorityPermission;
 68→};
 69→
 70→/** Input for creating a new agent. */
 71→export type CreateAgentInput = {
 72→  name: string;
 73→  description?: string;
 74→  runtime: "sandbox" | "external"; // "brain" not allowed via API
 75→  model?: string;
 76→  sandbox_config?: SandboxConfig;
 77→  authority_scopes?: AuthorityScopeInput[];
 78→};
 79→
 80→// ---------------------------------------------------------------------------
 81→// Output types
 82→// ---------------------------------------------------------------------------
 83→
 84→/** Agent summary returned from the list endpoint. */
 85→export type AgentListItem = {
 86→  id: string;
 87→  name: string;
 88→  description?: string;
 89→  runtime: AgentRuntime;
 90→  model?: string;
 91→  identity_id: string;
 92→  created_at: string;
 93→};
 94→
 95→/** Session summary for agent detail view. */
 96→export type SessionSummary = {
 97→  id: string;
 98→  started_at: string;
 99→  ended_at?: string;
100→  orchestrator_status?: string;
101→  summary?: string;
102→};
103→
104→/** Full agent detail returned from the detail endpoint. */
105→export type AgentDetail = {
106→  agent: AgentListItem & { sandbox_config?: SandboxConfig };
107→  identity: { id: string; name: string; type: string; role?: string };
108→  authority_scopes: Array<{ action: string; permission: string }>;
109→  sessions: SessionSummary[];
110→};
111→
112→/** Result of a successful agent creation. */
113→export type CreateAgentResult = {
114→  agent: AgentListItem;
115→  proxy_token?: string;
116→};
117→
118→/** Result of a successful agent deletion. */
119→export type DeleteAgentResult = {
120→  deleted: true;
121→  sessions_aborted: number;
122→};
