140→async function ensureSingleAgent(
141→  surreal: Surreal,
142→  workspaceRecord: RecordId<"workspace", string>,
143→  ownerIdentity: RecordId<"identity", string>,
144→  template: AgentTemplate,
145→): Promise<void> {
146→  const existing = await findExistingIdentity(surreal, workspaceRecord, "agent", template.role);
147→  if (existing) {
148→    log.info("identity.bootstrap.agent_exists", "Agent identity already exists, skipping", {
149→      workspaceId: workspaceRecord.id as string,
150→      agentType: template.agentType,
151→    });
152→    return;
153→  }
154→
155→  const now = new Date();
156→  const agentRecord = buildAgentRecord();
157→  const identityRecord = buildIdentityRecord();
158→
159→  // Create agent record with managed_by pointing to owner identity
160→  await surreal.create(agentRecord).content({
161→    agent_type: template.agentType,
162→    runtime: "brain" as const,
163→    name: template.name,
164→    managed_by: ownerIdentity,
165→    created_at: now,
166→  });
167→
168→  // Create agent identity hub
169→  await surreal.create(identityRecord).content({
170→    name: template.name,
171→    type: "agent" as const,
172→    role: template.role,
173→    workspace: workspaceRecord,
174→    created_at: now,
175→  });
176→
177→  // Create spoke edge from identity to agent
178→  await surreal
179→    .relate(identityRecord, new RecordId("identity_agent", randomUUID()), agentRecord, {
180→      added_at: now,
181→    })
182→    .output("after");
183→
184→  log.info("identity.bootstrap.agent_created", "Agent identity created", {
185→    workspaceId: workspaceRecord.id as string,
186→    agentType: template.agentType,
187→  });
188→}
