// ---------------------------------------------------------------------------
// Observation
// ---------------------------------------------------------------------------

export type ObservationSeverity = "info" | "warning" | "conflict";
export type ObservationStatus = "open" | "acknowledged" | "resolved";

export type CreateObservationOpts = {
  text: string;
  severity: ObservationSeverity;
  observationType?: string;
  sourceAgent: string;
  targetTable?: string;
  targetId?: string;
};

/**
 * Creates an observation record directly in SurrealDB.
 * Optionally links to a target entity via an observes edge.
 */
export async function createObservationDirectly(
  surreal: Surreal,
  workspaceId: string,
  opts: CreateObservationOpts,
): Promise<{ observationId: string; observationRecord: RecordId<"observation"> }> {
  const observationId = crypto.randomUUID();
  const observationRecord = new RecordId("observation", observationId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $obs CONTENT $content;`, {
    obs: observationRecord,
    content: {
      text: opts.text,
      severity: opts.severity,
      status: "open" as const,
      observation_type: opts.observationType,
      source_agent: opts.sourceAgent,
      workspace: workspaceRecord,
      created_at: new Date(),
    },
  });

  if (opts.targetTable && opts.targetId) {
    const targetRecord = new RecordId(opts.targetTable, opts.targetId);
    await surreal.query(
      `RELATE $obs->observes->$target SET added_at = time::now();`,
      { obs: observationRecord, target: targetRecord },
    );
  }

  return { observationId, observationRecord };
}

// ---------------------------------------------------------------------------
// Workspace Observations Query
// ---------------------------------------------------------------------------

/**
 * Queries all observations in a workspace, optionally filtered by source agent.
 */
export async function queryWorkspaceObservations(
  surreal: Surreal,
  workspaceId: string,
  sourceAgent?: string,
): Promise<Array<{
  id: RecordId;
  text: string;
  severity: string;
  status: string;
  source_agent: string;
  observation_type?: string;
  workspace: RecordId<"workspace">;
  created_at: string;
  updated_at?: string;
}>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);

  type ObsRow = {
    id: RecordId;
    text: string;
    severity: string;
    status: string;
    source_agent: string;
    observation_type?: string;
    workspace: RecordId<"workspace">;
    created_at: string;
    updated_at?: string;
  };

  if (sourceAgent) {
    const rows = (await surreal.query(
      `SELECT * FROM observation WHERE workspace = $ws AND source_agent = $agent ORDER BY created_at DESC;`,
      { ws: workspaceRecord, agent: sourceAgent },
    )) as Array<ObsRow[]>;
    return rows[0] ?? [];
  }

  const rows = (await surreal.query(
    `SELECT * FROM observation WHERE workspace = $ws ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<ObsRow[]>;
  return rows[0] ?? [];
}

// ---------------------------------------------------------------------------
// Task
// ---------------------------------------------------------------------------

export type CreateTaskOpts = {
  title: string;
  description?: string;
  status?: string;
  priority?: string;
  repoPath?: string;
};

/**
 * Creates a task record directly in SurrealDB.
 */
export async function createTaskDirectly(
  surreal: Surreal,
  workspaceId: string,
  opts: CreateTaskOpts,
): Promise<{ taskId: string; taskRecord: RecordId<"task"> }> {
  const taskId = crypto.randomUUID();
  const taskRecord = new RecordId("task", taskId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $task CONTENT $content;`, {
    task: taskRecord,
    content: {
      title: opts.title,
      description: opts.description,
      status: opts.status ?? "ready",
      priority: opts.priority,
      workspace: workspaceRecord,
      created_at: new Date(),
    },
  });

  return { taskId, taskRecord };
}

// ---------------------------------------------------------------------------
// Learning
// ---------------------------------------------------------------------------

export type CreateLearningOpts = {
  text: string;
  learningType?: "constraint" | "instruction" | "precedent";
  source?: "human" | "agent";
  status?: string;
  targetAgents?: string[];
};

/**
 * Creates a learning record directly in SurrealDB.
 */
export async function createLearningDirectly(
  surreal: Surreal,
  workspaceId: string,
  opts: CreateLearningOpts,
): Promise<{ learningId: string; learningRecord: RecordId<"learning"> }> {
  const learningId = crypto.randomUUID();
  const learningRecord = new RecordId("learning", learningId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $learning CONTENT $content;`, {
    learning: learningRecord,
    content: {
      text: opts.text,
      learning_type: opts.learningType ?? "instruction",
      status: opts.status ?? "active",
      source: opts.source ?? "human",
      priority: "medium",
      target_agents: opts.targetAgents ?? ["coding-agent"],
      workspace: workspaceRecord,
      created_at: new Date(),
    },
  });

  return { learningId, learningRecord };
}

// ---------------------------------------------------------------------------
// Proxy Token
// ---------------------------------------------------------------------------

/**
 * Seed a proxy_token record for acceptance tests and return the raw token.
 * The raw token is sent as `X-Brain-Auth` header; the server hashes it with
 * SHA-256 and looks up the hash in the `proxy_token` table.
 *
 * Optional `sessionId` and `intentId` link the token to an agent_session
 * and authorizing intent (R2 intent-gated-mcp governance).
 */
export async function seedProxyToken(
  surreal: Surreal,
  identityId: string,
  workspaceId: string,
  opts?: { sessionId?: string; intentId?: string },
): Promise<string> {
  const rawToken = `brn_test_${crypto.randomUUID()}`;
  const tokenHash = createHash("sha256").update(rawToken).digest("hex");
  const tokenId = crypto.randomUUID();
  const tokenRecord = new RecordId("proxy_token", tokenId);

  const content: Record<string, unknown> = {
    token_hash: tokenHash,
    workspace: new RecordId("workspace", workspaceId),
    identity: new RecordId("identity", identityId),
    expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000),
    revoked: false,
    created_at: new Date(),
  };
  if (opts?.sessionId) content.session = new RecordId("agent_session", opts.sessionId);
  if (opts?.intentId) content.intent = new RecordId("intent", opts.intentId);

  await surreal.query(`CREATE $rec CONTENT $content;`, {
    rec: tokenRecord,
    content,
  });

  return rawToken;
}

// ---------------------------------------------------------------------------
// Agent Session
// ---------------------------------------------------------------------------

/**
 * Creates an agent_session record directly in SurrealDB.
 * Use for orchestrator and MCP governance acceptance tests.
 */
export async function createAgentSessionDirectly(
  surreal: Surreal,
  workspaceId: string,
  opts?: {
    agent?: string;
    status?: string;
    sessionType?: string;
    provider?: string;
    taskId?: string;
  },
): Promise<{ sessionId: string; sessionRecord: RecordId<"agent_session"> }> {
  const sessionId = crypto.randomUUID();
  const sessionRecord = new RecordId("agent_session", sessionId);

  const content: Record<string, unknown> = {
    workspace: new RecordId("workspace", workspaceId),
    agent: opts?.agent ?? "claude",
    session_type: opts?.sessionType ?? "sandbox_agent",
    provider: opts?.provider ?? "local",
    orchestrator_status: opts?.status ?? "active",
    external_session_id: `ext-${sessionId}`,
    created_at: new Date(),
    started_at: new Date(),
  };
  if (opts?.taskId) content.task_id = new RecordId("task", opts.taskId);

  await surreal.query(`CREATE $record CONTENT $content;`, {
    record: sessionRecord,
    content,
  });

  return { sessionId, sessionRecord };
}

// ---------------------------------------------------------------------------
// Agent (Brain) Seeding
// ---------------------------------------------------------------------------

/**
 * Creates a brain agent directly in SurrealDB (for seeding test state).
 * Mirrors the identity bootstrap that creates system agents.
 * Writes `runtime` and `name` fields to match the agent schema.
 */
export async function seedBrainAgent(
  surreal: Surreal,
  workspaceId: string,
  name: string,
  opts?: { description?: string; agentType?: string },
): Promise<{ agentId: string; identityId: string }> {
  const agentId = crypto.randomUUID();
  const identityId = crypto.randomUUID();
  const agentRecord = new RecordId("agent", agentId);
  const identityRecord = new RecordId("identity", identityId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $agent CONTENT $content;`, {
    agent: agentRecord,
    content: {
      name,
      runtime: "brain",
      agent_type: opts?.agentType ?? "chat_agent",
      description: opts?.description ?? `Brain agent: ${name}`,
      managed_by: identityRecord,
      created_at: new Date(),
    },
  });

  await surreal.query(`CREATE $identity CONTENT $content;`, {
    identity: identityRecord,
    content: {
      name,
      type: "agent",
      role: opts?.agentType ?? "chat_agent",
      identity_status: "active",
      workspace: workspaceRecord,
      created_at: new Date(),
    },
  });

  await surreal.query(
    `RELATE $identity->identity_agent->$agent SET added_at = time::now();`,
    { identity: identityRecord, agent: agentRecord },
  );

  await surreal.query(
    `RELATE $identity->member_of->$workspace SET added_at = time::now(), role = "agent";`,
    { identity: identityRecord, workspace: workspaceRecord },
  );

  return { agentId, identityId };
}

// ---------------------------------------------------------------------------
// Graph Edge & Identity Verification Helpers
// ---------------------------------------------------------------------------

/**
 * Queries the identity record linked to an agent via identity_agent edge.
 */
export async function getIdentityForAgent(
  surreal: Surreal,
  agentId: string,
): Promise<Record<string, unknown> | undefined> {
  const agentRecord = new RecordId("agent", agentId);
  const rows = (await surreal.query(
    `SELECT VALUE in FROM identity_agent WHERE out = $agent LIMIT 1;`,
    { agent: agentRecord },
  )) as Array<Array<RecordId>>;
  const identityRecord = rows[0]?.[0];
  if (!identityRecord) return undefined;

  const identityRows = (await surreal.query(
    `SELECT * FROM $identity;`,
    { identity: identityRecord },
  )) as Array<Array<Record<string, unknown>>>;
  return identityRows[0]?.[0];
}

/**
 * Queries authorized_to edges for an identity.
 */
export async function getAuthorityEdgesForIdentity(
  surreal: Surreal,
  identityId: string,
): Promise<Array<{ action: string; permission: string }>> {
  const identityRecord = new RecordId("identity", identityId);
  const rows = (await surreal.query(
    `SELECT out.action AS action, permission FROM authorized_to WHERE in = $identity;`,
    { identity: identityRecord },
  )) as Array<Array<{ action: string; permission: string }>>;
  return rows[0] ?? [];
}

/**
 * Queries the member_of edge between an identity and workspace.
 */
export async function hasMemberOfEdge(
  surreal: Surreal,
  identityId: string,
  workspaceId: string,
): Promise<boolean> {
  const identityRecord = new RecordId("identity", identityId);
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id FROM member_of WHERE in = $identity AND out = $ws;`,
    { identity: identityRecord, ws: workspaceRecord },
  )) as Array<Array<{ id: RecordId }>>;
  return (rows[0]?.length ?? 0) > 0;
}

/**
 * Queries proxy_token records for an identity.
 */
export async function getProxyTokensForIdentity(
  surreal: Surreal,
  identityId: string,
): Promise<Array<Record<string, unknown>>> {
  const identityRecord = new RecordId("identity", identityId);
  const rows = (await surreal.query(
    `SELECT * FROM proxy_token WHERE identity = $identity;`,
    { identity: identityRecord },
  )) as Array<Array<Record<string, unknown>>>;
  return rows[0] ?? [];
}

// ---------------------------------------------------------------------------
// MCP Tool
// ---------------------------------------------------------------------------

/**
 * Creates an mcp_tool record directly in SurrealDB.
 * Use for tool registry and MCP governance acceptance tests.
 */
export async function createMcpToolDirectly(
  surreal: Surreal,
  workspaceId: string,
  opts: {
    name: string;
    toolkit: string;
    riskLevel?: string;
    description?: string;
    inputSchema?: Record<string, unknown>;
  },
): Promise<{ toolId: string; toolRecord: RecordId<"mcp_tool"> }> {
  const toolId = crypto.randomUUID();
  const toolRecord = new RecordId("mcp_tool", toolId);

  await surreal.query(`CREATE $rec CONTENT $content;`, {
    rec: toolRecord,
    content: {
      name: opts.name,
      toolkit: opts.toolkit,
      description: opts.description ?? `${opts.toolkit}:${opts.name} tool`,
      input_schema: opts.inputSchema ?? { type: "object", properties: {} },
      risk_level: opts.riskLevel ?? "low",
      workspace: new RecordId("workspace", workspaceId),
      status: "active",
      created_at: new Date(),
    },
  });

  return { toolId, toolRecord };
}

// ---------------------------------------------------------------------------
// Tool Grant (can_use edge)
// ---------------------------------------------------------------------------

/**
 * Creates a can_use relation edge granting an identity access to an MCP tool.
 */
export async function grantToolToIdentity(
  surreal: Surreal,
  identityId: string,
  toolId: string,
): Promise<void> {
  await surreal.query(
    `RELATE $identity->can_use->$tool SET granted_at = time::now();`,
    {
      identity: new RecordId("identity", identityId),
      tool: new RecordId("mcp_tool", toolId),
    },
  );
}

// ---------------------------------------------------------------------------
// Gates Edge (intent → agent_session)
// ---------------------------------------------------------------------------

/**
 * Creates a gates relation edge linking an authorized intent to an agent session.
 * Direction: intent → gates → agent_session (per schema).
 */
export async function createGatesEdge(
  surreal: Surreal,
  intentId: string,
  sessionId: string,
): Promise<void> {
  await surreal.query(
    `RELATE $intent->gates->$sess SET created_at = time::now();`,
    {
      intent: new RecordId("intent", intentId),
      sess: new RecordId("agent_session", sessionId),
    },
  );
}

