 1→BEGIN TRANSACTION;
 2→
 3→-- Step 1: Define name as optional so existing records pass validation
 4→DEFINE FIELD OVERWRITE name ON agent TYPE option<string>;
 5→
 6→-- Step 2: Define runtime as optional so existing records pass validation
 7→DEFINE FIELD OVERWRITE runtime ON agent TYPE option<string>;
 8→
 9→-- Backfill name from agent_type for records that don't have one
10→UPDATE agent SET name = agent_type WHERE name IS NONE OR name = '';
11→
12→-- Backfill runtime from agent_type
13→UPDATE agent SET runtime = IF agent_type IN ['code_agent', 'mcp'] THEN 'external'
14→  ELSE 'brain'
15→END
16→WHERE runtime IS NONE OR runtime = '';
17→
18→-- Step 3: Now all records have values — tighten to required with assertions
19→DEFINE FIELD OVERWRITE runtime ON agent TYPE string
20→  ASSERT $value IN ['brain', 'sandbox', 'external'];
21→
22→DEFINE FIELD OVERWRITE name ON agent TYPE string;
23→
24→-- Step 4: Remove agent_type from agent table (replaced by name + runtime)
25→REMOVE FIELD agent_type ON agent;
26→UPDATE agent UNSET agent_type;
27→
