  1→/**
  2→ * Agent Query Functions
  3→ *
  4→ * SurrealDB graph traversal, atomic creation transactions, and
  5→ * atomic deletion transactions for the agent CRUD module.
  6→ *
  7→ * All functions take `surreal` as first parameter (dependency injection).
  8→ * No module-level singletons or mutable state.
  9→ */
 10→import { randomUUID } from "node:crypto";
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import { HttpError } from "../http/errors";
 13→import {
 14→  generateProxyToken,
 15→  hashProxyToken,
 16→  computeExpiresAt,
 17→  readProxyTokenTtlDays,
 18→} from "../proxy/proxy-token-core";
 19→import {
 20→  AUTHORITY_ACTIONS,
 21→  type AgentDetail,
 22→  type AgentListItem,
 23→  type AuthorityAction,
 24→  type AuthorityPermission,
 25→  type CreateAgentInput,
 26→  type CreateAgentResult,
 27→  type DeleteAgentResult,
 28→  type SandboxConfig,
 29→  type SessionSummary,
 30→} from "./types";
 31→
 32→// ---------------------------------------------------------------------------
 33→// List agents
 34→// ---------------------------------------------------------------------------
 35→
 36→type ListAgentRow = {
 37→  id: RecordId<"identity_agent", string>;
 38→  agent_id: RecordId<"agent", string>;
 39→  agent_name: string;
 40→  agent_description?: string;
 41→  agent_runtime: string;
 42→  agent_model?: string;
 43→  identity_id: RecordId<"identity", string>;
 44→  agent_created_at: string | Date;
 45→};
 46→
 47→/**
 48→ * List all agents in a workspace via graph traversal:
 49→ * workspace <- member_of <- identity <- identity_agent -> agent
 50→ */
 51→export async function listAgents(
 52→  surreal: Surreal,
 53→  workspaceId: string,
 54→): Promise<AgentListItem[]> {
 55→  const workspaceRecord = new RecordId("workspace", workspaceId);
 56→
 57→  const [rows] = await surreal
 58→    .query<[ListAgentRow[]]>(
 59→      `SELECT
 60→        id,
 61→        out.id AS agent_id,
 62→        out.name AS agent_name,
 63→        out.description AS agent_description,
 64→        out.runtime AS agent_runtime,
 65→        out.model AS agent_model,
 66→        in.id AS identity_id,
 67→        out.created_at AS agent_created_at
 68→      FROM identity_agent
 69→      WHERE in IN (
 70→        SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
 71→      )
 72→      ORDER BY agent_created_at DESC;`,
 73→      { ws: workspaceRecord },
 74→    );
 75→
 76→  return rows.map(toAgentListItem);
 77→}
 78→
 79→function toAgentListItem(row: ListAgentRow): AgentListItem {
 80→  return {
 81→    id: row.agent_id.id as string,
 82→    name: row.agent_name,
 83→    ...(row.agent_description ? { description: row.agent_description } : {}),
 84→    runtime: row.agent_runtime as AgentListItem["runtime"],
 85→    ...(row.agent_model ? { model: row.agent_model } : {}),
 86→    identity_id: row.identity_id.id as string,
 87→    created_at: toISOString(row.agent_created_at),
 88→  };
 89→}
 90→
 91→// ---------------------------------------------------------------------------
 92→// Check agent name availability
 93→// ---------------------------------------------------------------------------
 94→
 95→/**
 96→ * Check if an agent name is available within a workspace.
 97→ * Returns true if the name is not taken.
 98→ */
 99→export async function checkAgentName(
100→  surreal: Surreal,
101→  workspaceId: string,
102→  name: string,
103→): Promise<boolean> {
104→  const workspaceRecord = new RecordId("workspace", workspaceId);
105→
106→  const [rows] = await surreal
107→    .query<[Array<{ agent_name: string }>]>(
108→      `SELECT out.name AS agent_name
109→      FROM identity_agent
110→      WHERE in IN (
111→        SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
112→      )
113→      AND out.name = $name
114→      LIMIT 1;`,
115→      { ws: workspaceRecord, name },
116→    );
117→
118→  return rows.length === 0;
119→}
120→
121→// ---------------------------------------------------------------------------
122→// Create agent (atomic transaction)
123→// ---------------------------------------------------------------------------
124→
125→/**
126→ * Create an agent with identity, membership, authority scopes, and
127→ * optional proxy token in a single atomic transaction.
128→ *
129→ * Steps:
130→ * 1. Validate name uniqueness within workspace
131→ * 2. CREATE agent record
132→ * 3. CREATE identity record
133→ * 4. RELATE identity -> identity_agent -> agent
134→ * 5. RELATE identity -> member_of -> workspace
135→ * 6. For each of 11 actions: RELATE identity -> authorized_to -> authority_scope
136→ * 7. For external agents: generate and store proxy token
137→ */
138→export async function createAgentTransaction(
139→  surreal: Surreal,
140→  workspaceId: string,
141→  input: CreateAgentInput,
142→  now: Date,
143→): Promise<CreateAgentResult> {
144→  // Pre-validate name uniqueness
145→  const nameAvailable = await checkAgentName(surreal, workspaceId, input.name);
146→  if (!nameAvailable) {
147→    throw new HttpError(409, `Agent name '${input.name}' is already taken in this workspace`);
148→  }
149→
150→  const workspaceRecord = new RecordId("workspace", workspaceId);
151→  const agentId = randomUUID();
152→  const identityId = randomUUID();
153→  const agentRecord = new RecordId("agent", agentId);
154→  const identityRecord = new RecordId("identity", identityId);
155→
156→  // Build permission map from input, defaulting unconfigured actions to "propose"
157→  const permissionMap = buildPermissionMap(input.authority_scopes);
158→
159→  // Look up all authority_scope records for our actions to get the OUT targets
160→  const [scopeRows] = await surreal
161→    .query<[Array<{ id: RecordId<"authority_scope", string>; action: string }>]>(
162→      `SELECT id, action FROM authority_scope
163→       WHERE action IN $actions
164→       AND workspace IS NONE;`,
165→      { actions: [...AUTHORITY_ACTIONS] },
166→    );
167→
168→  const scopeByAction = new Map(
169→    scopeRows.map((row) => [row.action, row.id]),
170→  );
171→
172→  // Build the transaction SQL
173→  const statements: string[] = [];
174→  const bindings: Record<string, unknown> = {
175→    agentRecord,
176→    identityRecord,
177→    wsRecord: workspaceRecord,
178→    agentName: input.name,
179→    agentRuntime: input.runtime,
180→    now,
181→  };
182→
183→  // Step 2: CREATE agent
184→  statements.push(
185→    `CREATE $agentRecord CONTENT {
186→      runtime: $agentRuntime,
187→      name: $agentName,
188→      ${input.description ? "description: $agentDescription," : ""}
189→      ${input.model ? "model: $agentModel," : ""}
190→      managed_by: $identityRecord,
191→      created_at: $now
192→      ${input.sandbox_config ? ", sandbox_config: $sandboxConfig" : ""}
193→    };`,
194→  );
195→
196→  if (input.description) bindings.agentDescription = input.description;
197→  if (input.model) bindings.agentModel = input.model;
198→  if (input.sandbox_config) bindings.sandboxConfig = input.sandbox_config;
199→
200→  // Step 3: CREATE identity
201→  statements.push(
202→    `CREATE $identityRecord CONTENT {
203→      name: $agentName,
204→      type: 'agent',
205→      role: 'custom',
206→      identity_status: 'active',
207→      workspace: $wsRecord,
208→      created_at: $now
209→    };`,
210→  );
211→
212→  // Step 4: RELATE identity -> identity_agent -> agent
213→  const identityAgentId = randomUUID();
214→  bindings.identityAgentRecord = new RecordId("identity_agent", identityAgentId);
215→  statements.push(
216→    `RELATE $identityRecord -> identity_agent -> $agentRecord
217→     CONTENT { added_at: $now };`,
218→  );
219→
220→  // Step 5: RELATE identity -> member_of -> workspace
221→  statements.push(
222→    `RELATE $identityRecord -> member_of -> $wsRecord
223→     CONTENT { role: 'agent', added_at: $now };`,
224→  );
225→
226→  // Step 6: RELATE identity -> authorized_to -> authority_scope for each action
227→  for (const action of AUTHORITY_ACTIONS) {
228→    const scopeRecord = scopeByAction.get(action);
229→    if (!scopeRecord) continue; // Skip if no global scope exists for this action
230→
231→    const permission = permissionMap.get(action) ?? "propose";
232→    const bindKey = `scope_${action}`;
233→    const permKey = `perm_${action}`;
234→    bindings[bindKey] = scopeRecord;
235→    bindings[permKey] = permission;
236→
237→    statements.push(
238→      `RELATE $identityRecord -> authorized_to -> $${bindKey}
239→       CONTENT { permission: $${permKey}, created_at: $now };`,
240→    );
241→  }
242→
243→  // Step 7: For external agents, generate proxy token
244→  let plainToken: string | undefined;
245→  if (input.runtime === "external") {
246→    plainToken = generateProxyToken();
247→    const tokenHash = hashProxyToken(plainToken);
248→    const ttlDays = readProxyTokenTtlDays();
249→    const expiresAt = computeExpiresAt(ttlDays, now);
250→    const proxyTokenId = randomUUID();
251→
252→    bindings.proxyTokenRecord = new RecordId("proxy_token", proxyTokenId);
253→    bindings.tokenHash = tokenHash;
254→    bindings.expiresAt = expiresAt;
255→
256→    statements.push(
257→      `CREATE $proxyTokenRecord CONTENT {
258→        token_hash: $tokenHash,
259→        workspace: $wsRecord,
260→        identity: $identityRecord,
261→        expires_at: $expiresAt,
262→        created_at: $now,
263→        revoked: false
264→      };`,
265→    );
266→  }
267→
268→  // Execute all statements in a single transaction
269→  const transactionSql = `BEGIN TRANSACTION;\n${statements.join("\n")}\nCOMMIT TRANSACTION;`;
270→  await surreal.query(transactionSql, bindings);
271→
272→  const agentListItem: AgentListItem = {
273→    id: agentId,
274→    name: input.name,
275→    ...(input.description ? { description: input.description } : {}),
276→    runtime: input.runtime,
277→    ...(input.model ? { model: input.model } : {}),
278→    identity_id: identityId,
279→    created_at: now.toISOString(),
280→  };
281→
282→  return {
283→    agent: agentListItem,
284→    ...(plainToken ? { proxy_token: plainToken } : {}),
285→  };
286→}
287→
288→function buildPermissionMap(
289→  scopes?: Array<{ action: AuthorityAction; permission: AuthorityPermission }>,
290→): Map<AuthorityAction, AuthorityPermission> {
291→  const map = new Map<AuthorityAction, AuthorityPermission>();
292→  if (!scopes) return map;
293→  for (const scope of scopes) {
294→    map.set(scope.action, scope.permission);
295→  }
296→  return map;
297→}
298→
299→// ---------------------------------------------------------------------------
300→// Get agent detail
301→// ---------------------------------------------------------------------------
302→
303→type AgentDetailRow = {
304→  id: RecordId<"agent", string>;
305→  name: string;
306→  description?: string;
307→  runtime: string;
308→  model?: string;
309→  sandbox_config?: SandboxConfig;
310→  created_at: string | Date;
311→};
312→
313→type IdentityRow = {
314→  id: RecordId<"identity", string>;
315→  name: string;
316→  type: string;
317→  role?: string;
318→};
319→
320→type AuthorizedToRow = {
321→  action: string;
322→  permission: string;
323→};
324→
325→type SessionRow = {
326→  id: RecordId<"agent_session", string>;
327→  started_at: string | Date;
328→  ended_at?: string | Date;
329→  orchestrator_status?: string;
330→  summary?: string;
331→};
332→
333→/**
334→ * Get full agent detail including identity, authority scopes, and
335→ * recent workspace sessions.
336→ */
337→export async function getAgentDetail(
338→  surreal: Surreal,
339→  workspaceId: string,
340→  agentId: string,
341→): Promise<AgentDetail | undefined> {
342→  const workspaceRecord = new RecordId("workspace", workspaceId);
343→  const agentRecord = new RecordId("agent", agentId);
344→
345→  // Query agent, identity, authorized_to edges, and sessions in one round-trip
346→  const results = await surreal
347→    .query<[AgentDetailRow[], IdentityRow[], AuthorizedToRow[], SessionRow[]]>(
348→      `SELECT id, name, description, runtime, model, sandbox_config, created_at
349→       FROM $agent;
350→
351→       SELECT id, name, type, role
352→       FROM identity
353→       WHERE id IN (
354→         SELECT VALUE in FROM identity_agent WHERE out = $agent
355→       )
356→       AND workspace = $ws
357→       LIMIT 1;
358→
359→       SELECT out.action AS action, permission
360→       FROM authorized_to
361→       WHERE in IN (
362→         SELECT VALUE in FROM identity_agent WHERE out = $agent
363→       )
364→       ORDER BY action ASC;
365→
366→       SELECT id, started_at, ended_at, orchestrator_status, summary
367→       FROM agent_session
368→       WHERE workspace = $ws
369→       ORDER BY started_at DESC
370→       LIMIT 20;`,
371→      { agent: agentRecord, ws: workspaceRecord },
372→    );
373→
374→  const [agentRows, identityRows, authorizedToRows, sessionRows] = results;
375→
376→  if (agentRows.length === 0 || identityRows.length === 0) {
377→    return undefined;
378→  }
379→
380→  const agentRow = agentRows[0];
381→  const identityRow = identityRows[0];
382→
383→  const agentListItem: AgentDetail["agent"] = {
384→    id: agentRow.id.id as string,
385→    name: agentRow.name,
386→    ...(agentRow.description ? { description: agentRow.description } : {}),
387→    runtime: agentRow.runtime as AgentListItem["runtime"],
388→    ...(agentRow.model ? { model: agentRow.model } : {}),
389→    identity_id: identityRow.id.id as string,
390→    created_at: toISOString(agentRow.created_at),
391→    ...(agentRow.sandbox_config ? { sandbox_config: agentRow.sandbox_config } : {}),
392→  };
393→
394→  return {
395→    agent: agentListItem,
396→    identity: {
397→      id: identityRow.id.id as string,
398→      name: identityRow.name,
399→      type: identityRow.type,
400→      ...(identityRow.role ? { role: identityRow.role } : {}),
401→    },
402→    authority_scopes: authorizedToRows.map((row) => ({
403→      action: row.action,
404→      permission: row.permission,
405→    })),
406→    sessions: sessionRows.map(toSessionSummary),
407→  };
408→}
409→
410→function toSessionSummary(row: SessionRow): SessionSummary {
411→  return {
412→    id: row.id.id as string,
413→    started_at: toISOString(row.started_at),
414→    ...(row.ended_at ? { ended_at: toISOString(row.ended_at) } : {}),
415→    ...(row.orchestrator_status ? { orchestrator_status: row.orchestrator_status } : {}),
416→    ...(row.summary ? { summary: row.summary } : {}),
417→  };
418→}
419→
420→// ---------------------------------------------------------------------------
421→// Delete agent (atomic transaction)
422→// ---------------------------------------------------------------------------
423→
424→/**
425→ * Delete an agent and all associated records atomically.
426→ *
427→ * Validates:
428→ * - Agent exists in workspace
429→ * - Agent is not a brain-managed agent
430→ * - Confirmation name matches agent name
431→ *
432→ * Deletes:
433→ * 1. authorized_to edges from identity
434→ * 2. proxy_token records for identity
435→ * 3. member_of edges from identity to workspace
436→ * 4. identity_agent edges to agent
437→ * 5. identity record
438→ * 6. agent record
439→ */
440→export async function deleteAgentTransaction(
441→  surreal: Surreal,
442→  workspaceId: string,
443→  agentId: string,
444→  confirmName: string,
445→): Promise<DeleteAgentResult> {
446→  const workspaceRecord = new RecordId("workspace", workspaceId);
447→  const agentRecord = new RecordId("agent", agentId);
448→
449→  // Validate agent exists and fetch identity
450→  const [agentRows, identityRows] = await surreal
451→    .query<[
452→      Array<{ id: RecordId; name: string; runtime: string }>,
453→      Array<{ id: RecordId<"identity", string> }>,
454→    ]>(
455→      `SELECT id, name, runtime FROM $agent;
456→
457→       SELECT VALUE in FROM identity_agent
458→       WHERE out = $agent
459→       AND in IN (
460→         SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
461→       )
462→       LIMIT 1;`,
463→      { agent: agentRecord, ws: workspaceRecord },
464→    );
465→
466→  if (agentRows.length === 0) {
467→    throw new HttpError(404, "Agent not found");
468→  }
469→
470→  const agent = agentRows[0];
471→
472→  if (agent.runtime === "brain") {
473→    throw new HttpError(403, "Cannot delete brain-managed agents");
474→  }
475→
476→  if (agent.name !== confirmName) {
477→    throw new HttpError(
478→      400,
479→      `Confirmation name '${confirmName}' does not match agent name '${agent.name}'`,
480→    );
481→  }
482→
483→  if (identityRows.length === 0) {
484→    throw new HttpError(404, "Agent identity not found in workspace");
485→  }
486→
487→  const identityRecord = identityRows[0] as unknown as RecordId<"identity", string>;
488→
489→  // Execute deletion in a single transaction
490→  await surreal.query(
491→    `BEGIN TRANSACTION;
492→     DELETE FROM authorized_to WHERE in = $identity;
493→     DELETE FROM proxy_token WHERE identity = $identity;
494→     DELETE FROM member_of WHERE in = $identity AND out = $ws;
495→     DELETE FROM identity_agent WHERE out = $agent;
496→     DELETE $identity;
497→     DELETE $agent;
498→     COMMIT TRANSACTION;`,
499→    {
500→      identity: identityRecord,
501→      agent: agentRecord,
502→      ws: workspaceRecord,
503→    },
504→  );
505→
506→  return {
507→    deleted: true,
508→    sessions_aborted: 0, // Deferred to R2
509→  };
510→}
511→
512→// ---------------------------------------------------------------------------
513→// Helpers
514→// ---------------------------------------------------------------------------
515→
516→function toISOString(value: string | Date): string {
517→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
518→}
